// Simulate Telegram message untuk testing
// Nanti ganti dengan real Telegram Trigger kalau sudah production

return {
  message: {
    text: '/order Kopi Susu-2, Teh Manis-1',
    chat: {
      id: 530532204
    },
    from: {
      username: 'testuser',
      first_name: 'Test Customer'
    }
  }
};

const text = $input.item.json.message.text;
const chatId = $input.item.json.message.chat.id;
const username = $input.item.json.message.from.username || 'Unknown';
const firstName = $input.item.json.message.from.first_name || 'Customer';

const orderText = text.replace('/order', '').trim();
const items = orderText.split(',').map(item => item.trim());

const orderItems = [];
for (const item of items) {
  const parts = item.split('-');
  if (parts.length === 2) {
    const productName = parts[0].trim();
    const quantity = parseInt(parts[1].trim());

    if (productName && quantity > 0) {
      orderItems.push({
        product_name: productName,
        quantity: quantity
      });
    }
  }
}

return {
  chat_id: chatId,
  username: username,
  customer_name: firstName,
  order_items: orderItems,
  order_text: orderText,
  timestamp: new Date().toISOString()
};

// Get order data dari Parse Order node
const orderData = $('Parse Order').item.json;

// Get products dari Google Sheets
const productsArray = $input.all();
const products = productsArray.map(item => item.json);

const validItems = [];
const invalidItems = [];
let totalAmount = 0;

// Validate each order item
for (const orderItem of orderData.order_items) {
  const product = products.find(p => 
    p.product_name.toLowerCase() === orderItem.product_name.toLowerCase()
  );

  if (product) {
    if (product.stock >= orderItem.quantity) {
      const subtotal = product.price * orderItem.quantity;
      validItems.push({
        product_id: product.product_id,
        product_name: product.product_name,
        price: product.price,
        quantity: orderItem.quantity,
        subtotal: subtotal
      });
      totalAmount += subtotal;
    } else {
      invalidItems.push({
        product_name: orderItem.product_name,
        reason: `Stok tidak cukup (tersedia: ${product.stock})`
      });
    }
  } else {
    invalidItems.push({
      product_name: orderItem.product_name,
      reason: 'Produk tidak ditemukan'
    });
  }
}

return {
  ...orderData,
  valid_items: validItems,
  invalid_items: invalidItems,
  total_amount: totalAmount,
  is_valid: invalidItems.length === 0 && validItems.length > 0
};

const data = $input.item.json;
const orderId = 'ORD-' + Date.now();

return {
  ...data,
  order_id: orderId,
  order_date: new Date().toISOString().split('T')[0],
  status: 'pending'
};

// Get data dari Generate Order ID node
const data = $('Generate Order ID').item.json;
const orderDetails = [];

for (const item of data.valid_items) {
  orderDetails.push({
    order_id: data.order_id,
    product_id: item.product_id,
    product_name: item.product_name,
    price: item.price,
    quantity: item.quantity,
    subtotal: item.subtotal
  });
}

return orderDetails;

// Get data dari Generate Order ID node
const data = $('Generate Order ID').item.json;

let message = `🧾 *INVOICE*\n\n`;
message += `Order ID: ${data.order_id}\n`;
message += `Tanggal: ${data.order_date}\n`;
message += `Customer: ${data.customer_name}\n\n`;
message += `*Detail Pesanan:*\n`;
message += `━━━━━━━━━━━━━━━━\n`;

for (const item of data.valid_items) {
  message += `${item.product_name}\n`;
  message += `  ${item.quantity} x Rp ${item.price.toLocaleString('id-ID')} = Rp ${item.subtotal.toLocaleString('id-ID')}\n\n`;
}

message += `━━━━━━━━━━━━━━━━\n`;
message += `*TOTAL: Rp ${data.total_amount.toLocaleString('id-ID')}*\n\n`;
message += `Status: ⏳ Pending\n\n`;
message += `Terima kasih sudah order! 🙏`;

return {
  chat_id: data.chat_id,
  message: message
};

const data = $input.item.json;

let message = `❌ *Order Gagal*\n\n`;

if (data.invalid_items.length > 0) {
  message += `*Produk bermasalah:*\n`;
  for (const item of data.invalid_items) {
    message += `• ${item.product_name}: ${item.reason}\n`;
  }
  message += `\n`;
}

if (data.valid_items.length === 0) {
  message += `Tidak ada produk yang valid.\n\n`;
}

message += `*Format order yang benar:*\n`;
message += `/order Produk1-qty, Produk2-qty\n\n`;
message += `Contoh:\n`;
message += `/order Kopi Susu-2, Teh Manis-1`;

return {
  chat_id: data.chat_id,
  message: message
};

const chatId = $input.item.json.message.chat.id;

const message = `🤖 *Telegram Store Bot*\n\n` +
  `*Cara Order:*\n` +
  `/order NamaProduk-qty, NamaProduk-qty\n\n` +
  `*Contoh:*\n` +
  `/order Kopi Susu-2, Teh Manis-1\n\n` +
  `*Produk Tersedia:*\n` +
  `• Kopi Susu (Rp 15,000)\n` +
  `• Teh Manis (Rp 10,000)\n` +
  `• Jus Jeruk (Rp 18,000)\n` +
  `• Air Mineral (Rp 5,000)\n\n` +
  `Selamat berbelanja! 🛒`;

return {
  chat_id: chatId,
  message: message
};
